// The HTTP node put the raw ICS text into $json.data
const icsText = $json.data;

// --- tiny ICS parser (VEVENT only) ---
function unfoldLines(s){
  const lines = s.replace(/\r/g,'').split('\n');
  const out = [];
  for (let i=0;i<lines.length;i++){
    const L = lines[i];
    if (i>0 && (L.startsWith(' ') || L.startsWith('\t'))) {
      out[out.length-1] += L.slice(1);
    } else out.push(L);
  }
  return out;
}

function icsToISO(s){
  if (!s) return null;
  if (/^\d{8}T\d{6}Z$/.test(s)) {
    const yyyy=s.slice(0,4), mm=s.slice(4,6), dd=s.slice(6,8);
    const hh=s.slice(9,11), mi=s.slice(11,13), ss=s.slice(13,15);
    return new Date(Date.UTC(+yyyy,+mm-1,+dd,+hh,+mi,+ss)).toISOString();
  }
  if (/^\d{8}$/.test(s)) {
    const yyyy=s.slice(0,4), mm=s.slice(4,6), dd=s.slice(6,8);
    return new Date(+yyyy,+mm-1,+dd).toISOString();
  }
  const d = new Date(s);
  return isNaN(d) ? null : d.toISOString();
}

const lines = unfoldLines(icsText);
const events = [];
let cur = null;

for (const line of lines){
  if (line === 'BEGIN:VEVENT') cur = {};
  else if (line === 'END:VEVENT'){ if (cur) events.push(cur); cur = null; }
  else if (cur){
    const idx = line.indexOf(':'); if (idx === -1) continue;
    const rawKey = line.slice(0, idx);
    const val = line.slice(idx+1);
    const key = rawKey.split(';')[0].toUpperCase();
    if (['UID','SUMMARY','DESCRIPTION','LOCATION','DTSTART','DTEND','DTSTAMP','URL'].includes(key)){
      cur[key] = val;
    }
  }
}

// map to clean JSON
const out = events.map(ev => ({
  uid: ev.UID || null,
  title: ev.SUMMARY || '',
  description: ev.DESCRIPTION || '',
  location: ev.LOCATION || '',
  startsAt: icsToISO(ev.DTSTART || null),
  endsAt: icsToISO(ev.DTEND || null),
  url: ev.URL || ''
}));

return out.map(e => ({ json: e }));

// Simple deterministic string hash (32-bit then hex)
function simpleHash(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) h = Math.imul(31, h) + str.charCodeAt(i) | 0;
  return (h >>> 0).toString(16);
}

function isAssignmentish(title, description) {
  const text = `${title} ${description}`.toLowerCase();
  const keywords = ['assignment','homework','hw','quiz','exam','project','lab','report','due'];
  return keywords.some(k => text.includes(k));
}

function extractSubmitLink(desc = '') {
  // Convert any literal "\n" sequences into real newlines
  const normalized = String(desc).replace(/\\n/g, '\n');
  const m = normalized.match(/https:\/\/d2l\.msu\.edu\/d2l\/lms\/dropbox\/user\/folder_submit_files[^\s]+/);
  return m ? m[0] : 'No Submission Link Available';
}

const results = [];

for (const item of items) {
  const e = item.json;
  const title = e.title || '';
  const desc  = e.description || '';

  if (!isAssignmentish(title, desc)) continue;

  const uid = e.uid || `${title}|${e.startsAt || ''}`;
  const uidHash = simpleHash(uid);
  const due = e.startsAt || e.endsAt || null;

  results.push({
    json: {
      uid,
      uidHash,
      todoTitle: title.trim(),
      due,
      sourceUrl: e.url || '',
      notes: extractSubmitLink(desc),   // ✅ link or fallback text
      courseLabel: e.courseLabel || null
    }
  });
}

return results;

