const DAYS_AHEAD = 14;
const INCLUDE_PAST_DAYS = 0;

function inWindow(iso) {
  if (!iso) return false;
  const now = new Date();
  const start = new Date(now.getTime() - INCLUDE_PAST_DAYS * 24 * 60 * 60 * 1000);
  const end   = new Date(now.getTime() + DAYS_AHEAD * 24 * 60 * 60 * 1000);
  const d = new Date(iso);
  return d >= start && d <= end;
}

const out = [];

for (const { json: e } of items) {
  const due = e.startsAt || e.endsAt || null;

  // ✅ Must be in date window AND title contains "- Due"
  if (inWindow(due) && typeof e.title === "string" && e.title.includes("- Due")) {
    out.push({ json: e });
  }
}

return out;

/**
 * INPUT: items[] from Todoist active-tasks node
 *  - Each item should have at least: { id || task_id, content, description }
 *
 * OUTPUT: one item:
 *  { idByHash: { [uidHashLower]: String(task_id) } }
 */

const UID_VISIBLE_RE = /\[uid:([a-f0-9]{8})\]/i;

// Zero-width mapping (base-4 alphabet)
const ZW = ['\u200B', '\u200C', '\u200D', '\u2060'];
const START = '\u2063';
const END   = '\u2062';

function decodeInvisibleUID(str) {
  if (!str) return null;
  const startIdx = str.indexOf(START);
  if (startIdx === -1) return null;
  const endIdx = str.indexOf(END, startIdx + 1);
  if (endIdx === -1) return null;
  const payload = str.slice(startIdx + START.length, endIdx);
  if (!payload) return null;

  const base4 = [];
  for (const ch of payload) {
    const d = ZW.indexOf(ch);
    if (d === -1) return null;
    base4.push(d);
  }
  if (base4.length % 2 !== 0) return null;

  const hex = [];
  for (let i = 0; i < base4.length; i += 2) {
    const val = base4[i] * 4 + base4[i + 1];
    hex.push(val.toString(16));
  }
  const out = hex.join('').toLowerCase();
  return /^[0-9a-f]{8}$/.test(out) ? out : null;
}

const idByHash = {};

for (const { json } of items) {
  const taskId = String(json.id ?? json.task_id ?? '');
  if (!taskId) continue;

  const content = String(json.content || '');
  const description = String(json.description || '');

  let uid =
    decodeInvisibleUID(content) ||
    (content.match(UID_VISIBLE_RE)?.[1]?.toLowerCase()) ||
    (description.match(UID_VISIBLE_RE)?.[1]?.toLowerCase()) ||
    null;

  if (uid) idByHash[uid] = taskId;
}

return [{ json: { idByHash } }];

/**
 * Plan Actions (stateless, Pattern A)
 *
 * Inputs (merged):
 *  - Many "assignment" items having { uidHash, todoTitle, due, notes, sourceUrl }
 *  - One item having { idByHash } from Index Active
 *  - One item having { completedByHash } from Index Completed
 *  - (Optional, from Restore Webhook path) { forceRecreate: true }
 *
 * Output:
 *  - For each assignment: route in {create|update|skip_completed}
 *    and include task_id when updating.
 */

let idByHash = {};
let completedByHash = {};
const assignments = [];
let forceRecreate = false; // <- ephemeral flag injected by webhook execution

// Separate payloads
for (const it of items) {
  const j = it.json || {};
  if (j.idByHash && typeof j.idByHash === 'object') {
    idByHash = j.idByHash;
  } else if (j.completedByHash && typeof j.completedByHash === 'object') {
    completedByHash = j.completedByHash;
  } else if (j.uidHash) {
    assignments.push(j);
  } else if (j.forceRecreate === true) {
    forceRecreate = true;
  }
}

const out = [];

for (const a of assignments) {
  const hash = String(a.uidHash || '').toLowerCase();

  // Normal mode: skip if previously completed
  // Force mode: DO NOT skip
  if (!forceRecreate && completedByHash[hash]) {
    out.push({ json: { ...a, route: 'skip_completed' } });
    continue;
  }

  const activeId = idByHash[hash];

  if (activeId) {
    // Idempotent update
    out.push({ json: { ...a, task_id: activeId, route: 'update' } });
  } else {
    out.push({ json: { ...a, route: 'create' } });
  }
}

return out;

/**
 * INPUT: EITHER
 *  A) One item whose json is the full /completed/get_all object:
 *     { items: [...], projects: {...}, sections: {...} }
 *  B) Many items where each json IS a completed item (if split upstream)
 *
 * OUTPUT: one item:
 *  { completedByHash: { [uidHashLower]: true } }
 */

const UID_VISIBLE_RE = /\[uid:([a-f0-9]{8})\]/i;

// Zero-width mapping (base-4 alphabet)
const ZW = ['\u200B', '\u200C', '\u200D', '\u2060'];
const START = '\u2063';
const END   = '\u2062';

function decodeInvisibleUID(str) {
  if (!str) return null;
  const s = String(str);
  const i = s.indexOf(START);
  if (i === -1) return null;
  const j = s.indexOf(END, i + 1);
  if (j === -1) return null;
  const payload = s.slice(i + START.length, j);
  if (!payload) return null;

  const base4 = [];
  for (const ch of payload) {
    const d = ZW.indexOf(ch);
    if (d === -1) return null;
    base4.push(d);
  }
  if (base4.length % 2 !== 0) return null;

  let hex = '';
  for (let k = 0; k < base4.length; k += 2) {
    const val = base4[k] * 4 + base4[k + 1]; // 0..15
    hex += val.toString(16);
  }
  return /^[0-9a-f]{8}$/.test(hex) ? hex : null;
}

function* iterRows(inputItems) {
  for (const it of inputItems) {
    const j = it.json || {};
    if (Array.isArray(j.items)) {
      for (const row of j.items) yield row;   // unwrap wrapper
    } else {
      yield j; // already a row
    }
  }
}

const completedByHash = {};

for (const row of iterRows(items)) {
  const content = String(row.content || '');
  const description = String(row.description || ''); // usually absent

  const invisible = decodeInvisibleUID(content);
  const visible =
    (content.match(UID_VISIBLE_RE)?.[1]) ||
    (description.match(UID_VISIBLE_RE)?.[1]) ||
    null;

  const uid = (invisible || visible || '').toLowerCase();
  if (uid) completedByHash[uid] = true;
}

return [{ json: { completedByHash } }];

/**
 * Input: array of Todoist tasks (Search Tasks)
 * Output: one item with { commands } for Sync API item_reorder
 *
 * Sort: newest due → oldest due → no due
 */
function toMillis(due) {
  if (!due) return null;
  // Prefer due.datetime, else due.date at 23:59:59 to keep “date-only” comparable
  if (due.datetime) return Date.parse(due.datetime);
  if (due.date) return Date.parse(due.date + 'T23:59:59Z');
  return null;
}

const tasks = items.map(i => i.json);

// Sort asc by due-millis (nulls last) ⇒ closest → furthest → none
tasks.sort((a, b) => {
  const A = toMillis(a.due);
  const B = toMillis(b.due);
  if (A === null && B === null) return 0;
  if (A === null) return 1;   // A (no date) goes after B
  if (B === null) return -1;  // B (no date) goes after A
  return A - B; // smaller millis (earlier/closer) first
});

// Build items → child_order
const itemsArg = tasks.map((t, idx) => ({
  id: String(t.id),
  child_order: idx + 1
}));

// Minimal UUID generator
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const cmd = {
  type: "item_reorder",
  uuid: uuidv4(),
  args: { items: itemsArg }
};

return [{ json: { commands: [cmd] } }];

/**
 * INPUT: items[] with { todoTitle, uidHash }
 * OUTPUT: same items, adding { contentWithUID } built from CLEANED title + invisible UID
 */

const ZW = ['\u200B', '\u200C', '\u200D', '\u2060']; // base-4 alphabet
const START = '\u2063'; // INVISIBLE SEPARATOR
const END   = '\u2062'; // INVISIBLE TIMES

function encodeInvisibleUID(uidHex) {
  const uid = String(uidHex || '').toLowerCase();
  if (!/^[0-9a-f]{8}$/.test(uid)) return '';
  const outChars = [];
  for (const h of uid) {
    const n = parseInt(h, 16);
    const hi = Math.floor(n / 4);
    const lo = n % 4;
    outChars.push(ZW[hi], ZW[lo]);
  }
  return START + outChars.join('') + END;
}

// strip " - Due" / "– Due" (case-insensitive), collapse spaces, trim
function cleanTitle(s) {
  if (typeof s !== 'string') return s;
  return s
    .replace(/\s*[-–]\s*due\b/i, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

const out = [];
for (const { json } of items) {
  const base = String(json.todoTitle || '');
  const clean = cleanTitle(base);
  const enc = encodeInvisibleUID(json.uidHash);
  out.push({ json: { ...json, contentWithUID: clean + enc } });
}

return out;

