/**
 * Extract a course code from TITLE or LOCATION and attach:
 *  - courseLabel  (e.g., "MSE-320") -> for Todoist labels
 *  - coursePretty (e.g., "MSE 320") -> optional for title prefix
 */
function extractCourseFrom(title = '', location = '') {
  const T = String(title).toUpperCase();
  let L = String(location).toUpperCase();

  // Strip leading term prefix like FS25-, SS25-, FA24-, SP26- from LOCATION
  L = L.replace(/^(FS|SS|FA|SP)\d{2}-/, '');

  // Pattern: DEPT (2–4 letters) + optional hyphen/space + NUMBER (3–4 digits + optional letter)
  const RX = /\b([A-Z]{2,4})[-\s]?(\d{3,4}[A-Z]?)\b/;

  let m = T.match(RX);
  if (!m) m = L.match(RX);
  if (!m) return { label: null, pretty: null };

  const dept = m[1];
  const num  = m[2];
  return {
    label: `${dept}-${num}`,   // Capitalized label, e.g. "MSE-320"
    pretty: `${dept} ${num}`   // Pretty with space, e.g. "MSE 320"
  };
}

return items.map(i => {
  const j = i.json || {};
  const { label, pretty } = extractCourseFrom(j.title || '', j.location || '');
  j.courseLabel = label;
  j.coursePretty = pretty;
  return { json: j };
});

